UPDATE /* @SQLID=SUB0501_01-03_1#Sql003 */ 
    PSITE_T4N_INFO 

        T4N_TITLE = #{ req.title }
        , T4N_CONTENT = #{ req.contents }

            , T4N_FILE1 = #{ req.attachFile1 }


            , T4N_FILE2 = #{ req.attachFile2 }


            , T4N_FILE3 = #{ req.attachFile3 }

        , T4N_CAT1 = TO_NUMBER(#{ req.documentKindInput1 })
        , T4N_FILE_COM1 = #{ req.attachFileComment1 }
        , T4N_FILE_COM2 = #{ req.attachFileComment2 }
        , T4N_FILE_COM3 = #{ req.attachFileComment3 }
        , T4N_URL = #{ req.url }
        , COR_URL_COM = #{ req.urlComment }
        , COR_REFERENCE_CONDITION = #{ req.corReferenceCondition }
        , COR_DISCLAIMER = #{ req.disclaimer }
        , COR_READ_FLG = #{ req.corReadFlg }
        , COR_UPDATE_DATE = IFA_DATE_UTIL.IFA_GET_DATE
        , COR_UPDATE_BY = #{ req.updateUser }

WHERE 
    T4N_ID = TO_NUMBER(#{req.notificationId})
